<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    locks: list[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 已获取的锁文件路径</span></span>
